import{_ as t,o as i,c as s,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"2. Production (Distributeur)","description":"","frontmatter":{"title":"2. Production (Distributeur)"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md","filePath":"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md"}'),o={name:"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md"};function a(n,e,d,l,u,p){return i(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="etape-2-production-co-branding" tabindex="-1">Étape 2 : Production &amp; Co-branding <a class="header-anchor" href="#etape-2-production-co-branding" aria-label="Permalink to &quot;Étape 2 : Production &amp; Co-branding&quot;">​</a></h1><p>Une fois votre brief envoyé, c&#39;est le Distributeur qui prend le relais pour concevoir l&#39;email. Voici pourquoi et comment cela fonctionne.</p><hr class="my-6"><h2 class="text-blue-200 mb-4">Pourquoi ce n&#39;est pas vous qui créez l&#39;email ?</h2><div style="background-color:#eff6ff;border:2px solid #2563eb;border-radius:8px;padding:24px;margin-bottom:40px;"><h3 class="mt-0 text-purple-200">🤝 La force de l&#39;Endorsement (Recommandation)</h3><p class="fs-4 mb-2">L&#39;objectif n&#39;est pas d&#39;envoyer une publicité brute, mais une <strong>recommandation de la part du partenaire</strong>.</p><p class="mb-0">Les abonnés du Distributeur lui font confiance. Pour maximiser le taux d&#39;ouverture et de clic, l&#39;email doit respecter les codes graphiques et le ton habituel de la newsletter qu&#39;ils reçoivent chaque semaine.</p></div><h2 class="text-grey-dk-000 mb-4">À quoi va ressembler votre campagne ?</h2><div style="display:flex;gap:20px;flex-wrap:wrap;margin-bottom:40px;"><div style="flex:1;min-width:300px;border:1px solid #2da44e;background-color:#f6fff8;border-radius:8px;padding:20px;"><h3 class="mt-0 text-green-200">✅ Le Résultat Attendu (Natif)</h3><ul class="mb-0 fs-3 pl-4"><li class="mb-2"><strong>Header Partenaire :</strong> Le logo et le menu du Distributeur restent en haut pour rassurer l&#39;abonné.</li><li class="mb-2"><strong>Édito d&#39;intro :</strong> Le Distributeur rédige une phrase d&#39;accroche (ex: <em>&quot;Aujourd&#39;hui, nous vous présentons notre coup de cœur...&quot;</em>).</li><li class="mb-2"><strong>Vos Assets :</strong> Vos visuels et votre offre sont intégrés au centre, mais avec les boutons et polices du partenaire.</li></ul></div><div style="flex:1;min-width:300px;border:1px solid #cf222e;background-color:#fff5f5;border-radius:8px;padding:20px;"><h3 class="mt-0 text-red-200">❌ Ce qui est évité (Full Brand)</h3><p class="fs-3">Nous évitons d&#39;envoyer un email qui ressemble à 100% à votre site web sans mention du partenaire.</p><p class="mb-0 fs-2 text-grey-dk-000"><em>Pourquoi ? Car cela crée une dissonance cognitive chez l&#39;abonné (&quot;Pourquoi je reçois ça ?&quot;), augmente le taux de désabonnement et fait chuter la performance.</em></p></div></div><h2 class="text-grey-dk-000 mb-4">Le flux de production</h2><div style="display:flex;flex-direction:column;gap:15px;margin-bottom:40px;"><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;background:#fff;display:flex;align-items:center;gap:20px;"><div style="font-size:24px;min-width:40px;text-align:center;">🎨</div><div><strong class="fs-4 d-block">1. Conception</strong><span class="fs-2 text-grey-dk-000">Le Distributeur (ou le Studio getinside) assemble l&#39;email en utilisant les éléments de votre brief.</span></div></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;background:#fff;display:flex;align-items:center;gap:20px;"><div style="font-size:24px;min-width:40px;text-align:center;">⚙️</div><div><strong class="fs-4 d-block">2. Intégration Technique</strong><span class="fs-2 text-grey-dk-000">Les liens de tracking sont générés et insérés pour suivre vos ventes. Le code est optimisé pour la délivrabilité.</span></div></div><div style="border:1px solid #e1e4e8;border-radius:8px;padding:20px;background:#fff;display:flex;align-items:center;gap:20px;"><div style="font-size:24px;min-width:40px;text-align:center;">👀</div><div><strong class="fs-4 d-block">3. Review Interne</strong><span class="fs-2 text-grey-dk-000">L&#39;équipe getinside vérifie la qualité technique avant de vous soumettre le résultat.</span></div></div></div><div style="background-color:#f0f8ff;border:1px solid #2d6fd6;border-radius:8px;padding:24px;margin-bottom:40px;"><h3 class="mt-0 text-blue-200">🔄 Flexibilité : Vos liens sont dynamiques !</h3><p class="fs-3 mb-2">Une erreur dans le brief ? Vous changez de Landing Page à la dernière minute ?</p><p class="mb-2">Pas de panique. Comme pour nos QR codes, les liens de tracking emails sont <strong>dynamiques</strong>.</p><ul class="mb-0 fs-3 pl-4"><li>Vous pouvez modifier l&#39;URL de destination finale à tout moment dans l&#39;onglet <strong>&quot;Configuration et Suivi&quot;</strong> de votre campagne.</li><li>La mise à jour est <strong>instantanée</strong>, même si le Distributeur a déjà intégré le lien ou si la campagne est prête à partir.</li></ul></div><div class="p-4 bg-grey-lt-000 border rounded-1"><h4 class="mt-0">Et ensuite ?</h4><p class="mb-0">Dès que la création est prête, vous recevez une notification pour passer à l&#39;étape de <strong>Validation (BAT)</strong>.</p></div>',11)])])}const g=t(o,[["render",a]]);export{m as __pageData,g as default};
